+/**
+ * Recur schema interface.
+ */
+export interface RecurSchema extends BaseSchema<RecurSchema, RecurSchema, never> {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recur';
+}
+
+/**
+ * Recursive input type.
+ */
+type RecursiveInput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
+  ReplaceRecur<InferInput<TSchema>, RecursiveInput<TSchema>>;
+
+/**
+ * Recursive output type.
+ */
+type RecursiveOutput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
+  ReplaceRecur<InferOutput<TSchema>, RecursiveOutput<TSchema>>;
+
+/**
+ * Replaces recur schema references in a type.
+ */
+type ReplaceRecur<TValue, TRecur> = TValue extends RecurSchema
+  ? TRecur
+  : TValue extends Map<infer TKey, infer TValue>
+    ? Map<ReplaceRecur<TKey, TRecur>, ReplaceRecur<TValue, TRecur>>
+    : TValue extends Set<infer TValue>
+      ? Set<ReplaceRecur<TValue, TRecur>>
+      : TValue extends readonly unknown[]
+        ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TRecur> }
+        : TValue extends object
+          ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TRecur> }
+          : TValue;
+
+/**
+ * Recursive schema type.
+ */
+export type RecursiveSchema<
+  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> = Omit<TSchema, '~standard' | '~types'> & {
+  /**
+   * The Standard Schema properties.
+   *
+   * @internal
+   */
+  readonly '~standard': StandardProps<RecursiveInput<TSchema>, RecursiveOutput<TSchema>>;
+  /**
+   * The input, output and issue type.
+   *
+   * @internal
+   */
+  readonly '~types'?: {
+    readonly input: RecursiveInput<TSchema>;
+    readonly output: RecursiveOutput<TSchema>;
+    readonly issue: InferIssue<TSchema>;
+  } | undefined;
+};
+
+/**
+ * Placeholder schema for recursive references.
+ */
+export const Recur: RecurSchema = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    throw new TypeError('Recur must be wrapped with recursive.');
+  },
+  '~run'() {
+    throw new TypeError('Recur must be wrapped with recursive.');
+  },
+};
+
+/**
+ * Creates a recursive schema.
+ *
+ * @param schema The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TSchema): RecursiveSchema<TSchema> {
+  let recursiveSchema: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
+  const recurSchema = lazy(() => recursiveSchema);
+  recursiveSchema = _replaceRecur(schema, recurSchema) as TSchema;
+  return recursiveSchema as RecursiveSchema<TSchema>;
+}
+
+/**
+ * Replaces recur placeholders in a schema.
+ *
+ * @internal
+ */
+function _replaceRecur(
+  value: unknown,
+  recurSchema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+  visited = new WeakMap<object, unknown>()
+): unknown {
+  if (value === Recur) {
+    return recurSchema;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+  const cached = visited.get(value);
+  if (cached) {
+    return cached;
+  }
+  if (Array.isArray(value)) {
+    const copy: unknown[] = [];
+    visited.set(value, copy);
+    for (const item of value) {
+      copy.push(_replaceRecur(item, recurSchema, visited));
+    }
+    return copy;
+  }
+  const copy = Object.create(
+    Object.getPrototypeOf(value),
+    Object.getOwnPropertyDescriptors(value)
+  ) as Record<PropertyKey, unknown>;
+  visited.set(value, copy);
+  for (const key of Reflect.ownKeys(copy)) {
+    const descriptor = Object.getOwnPropertyDescriptor(copy, key);
+    if (descriptor && 'value' in descriptor) {
+      copy[key] = _replaceRecur(descriptor.value, recurSchema, visited);
+    }
+  }
+  return copy;
+}
